{
  "mode": "method",
  "tests": [
    {
      "name": "valid_member_download",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": true
      },
      "output": {
        "can_download": true
      },
      "notes": "Valid member who submitted to the challenge should be able to download submissions."
    },
    {
      "name": "non_member_download",
      "input": {
        "member_id": "54321",
        "challenge_id": "67890",
        "submitted": false
      },
      "output": {
        "can_download": false
      },
      "notes": "Non-member who did not submit should not be able to download submissions."
    },
    {
      "name": "member_without_submission",
      "input": {
        "member_id": "67890",
        "challenge_id": "12345",
        "submitted": false
      },
      "output": {
        "can_download": false
      },
      "notes": "Member who has not submitted should not be able to download."
    },
    {
      "name": "member_with_submission",
      "input": {
        "member_id": "11111",
        "challenge_id": "22222",
        "submitted": true
      },
      "output": {
        "can_download": true
      },
      "notes": "Member who has submitted should be able to download."
    },
    {
      "name": "multiple_submissions",
      "input": {
        "member_id": "33333",
        "challenge_id": "44444",
        "submitted": true
      },
      "output": {
        "can_download": true
      },
      "notes": "Member with multiple submissions should still be able to download."
    },
    {
      "name": "challenge_not_found",
      "input": {
        "member_id": "55555",
        "challenge_id": "99999",
        "submitted": true
      },
      "output": {
        "error": "Challenge not found"
      },
      "notes": "Should handle case where challenge does not exist."
    },
    {
      "name": "invalid_member_id",
      "input": {
        "member_id": "invalid_id",
        "challenge_id": "67890",
        "submitted": true
      },
      "output": {
        "error": "Invalid member ID"
      },
      "notes": "Should handle case where member ID is invalid."
    },
    {
      "name": "no_submission_no_download",
      "input": {
        "member_id": "22222",
        "challenge_id": "33333",
        "submitted": false
      },
      "output": {
        "can_download": false
      },
      "notes": "Ensures that a member without submission cannot download."
    }
  ],
  "assumptions": "Members must submit to a challenge to download submissions. Invalid IDs should be handled gracefully.",
  "notes": "Tests cover valid and invalid scenarios for downloading submissions."
}
